1	import { createFileRoute } from "@tanstack/react-router";
2	import { useQuery } from "@tanstack/react-query";
3	import { useCallback, useState } from "react";
4	import { type ProviderKind } from "@t3tools/contracts";
5	import { getModelOptions, normalizeModelSlug } from "@t3tools/shared/model";
6	import { ZapIcon } from "lucide-react";
7	
8	import {
9	  APP_SERVICE_TIER_OPTIONS,
10	  MAX_CUSTOM_MODEL_LENGTH,
11	  shouldShowFastTierIcon,
12	  useAppSettings,
13	} from "../appSettings";
14	import { isElectron } from "../env";
15	import { useTheme } from "../hooks/useTheme";
16	import { serverConfigQueryOptions } from "../lib/serverReactQuery";
17	import { ensureNativeApi } from "../nativeApi";
18	import { preferredTerminalEditor } from "../terminal-links";
19	import { Button } from "../components/ui/button";
20	import { Input } from "../components/ui/input";
21	import { Select, SelectItem, SelectPopup, SelectTrigger, SelectValue } from "../components/ui/select";
22	import { Switch } from "../components/ui/switch";
23	import { SidebarInset } from "~/components/ui/sidebar";
24	
25	const THEME_OPTIONS = [
26	  {
27	    value: "system",
28	    label: "System",
29	    description: "Match your OS appearance setting.",
30	  },
31	  {
32	    value: "light",
33	    label: "Light",
34	    description: "Always use the light theme.",
35	  },
36	  {
37	    value: "dark",
38	    label: "Dark",
39	    description: "Always use the dark theme.",
40	  },
41	] as const;
42	
43	const MODEL_PROVIDER_SETTINGS: Array<{
44	  provider: ProviderKind;
45	  title: string;
46	  description: string;
47	  placeholder: string;
48	  example: string;
49	}> = [
50	  {
51	    provider: "codex",
52	    title: "Codex",
53	    description: "Save additional Codex model slugs for the picker and `/model` command.",
54	    placeholder: "your-codex-model-slug",
55	    example: "gpt-6.7-codex-ultra-preview",
56	  },
57	] as const;
58	
59	function getCustomModelsForProvider(
60	  settings: ReturnType<typeof useAppSettings>["settings"],
61	  provider: ProviderKind,
62	) {
63	  switch (provider) {
64	    case "codex":
65	    default:
66	      return settings.customCodexModels;
67	  }
68	}
69	
70	function getDefaultCustomModelsForProvider(
71	  defaults: ReturnType<typeof useAppSettings>["defaults"],
72	  provider: ProviderKind,
73	) {
74	  switch (provider) {
75	    case "codex":
76	    default:
77	      return defaults.customCodexModels;
78	  }
79	}
80	
81	function patchCustomModels(provider: ProviderKind, models: string[]) {
82	  switch (provider) {
83	    case "codex":
84	    default:
85	      return { customCodexModels: models };
86	  }
87	}
88	
89	function SettingsRouteView() {
90	  const { theme, setTheme, resolvedTheme } = useTheme();
91	  const { settings, defaults, updateSettings } = useAppSettings();
92	  const serverConfigQuery = useQuery(serverConfigQueryOptions());
93	  const [isOpeningKeybindings, setIsOpeningKeybindings] = useState(false);
94	  const [openKeybindingsError, setOpenKeybindingsError] = useState<string | null>(null);
95	  const [customModelInputByProvider, setCustomModelInputByProvider] = useState<
96	    Record<ProviderKind, string>
97	  >({
98	    codex: "",
99	  });
100	  const [customModelErrorByProvider, setCustomModelErrorByProvider] = useState<
101	    Partial<Record<ProviderKind, string | null>>
102	  >({});
103	
104	  const codexBinaryPath = settings.codexBinaryPath;
105	  const codexHomePath = settings.codexHomePath;
106	  const codexServiceTier = settings.codexServiceTier;
107	  const keybindingsConfigPath = serverConfigQuery.data?.keybindingsConfigPath ?? null;
108	
109	  const openKeybindingsFile = useCallback(() => {
110	    if (!keybindingsConfigPath) return;
111	    setOpenKeybindingsError(null);
112	    setIsOpeningKeybindings(true);
113	    const api = ensureNativeApi();
114	    void api.shell
115	      .openInEditor(keybindingsConfigPath, preferredTerminalEditor())
116	      .catch((error) => {
117	        setOpenKeybindingsError(
118	          error instanceof Error ? error.message : "Unable to open keybindings file.",
119	        );
120	      })
121	      .finally(() => {
122	        setIsOpeningKeybindings(false);
123	      });
124	  }, [keybindingsConfigPath]);
125	
126	  const addCustomModel = useCallback((provider: ProviderKind) => {
127	    const customModelInput = customModelInputByProvider[provider];
128	    const customModels = getCustomModelsForProvider(settings, provider);
129	    const normalized = normalizeModelSlug(customModelInput, provider);
130	    if (!normalized) {
131	      setCustomModelErrorByProvider((existing) => ({
132	        ...existing,
133	        [provider]: "Enter a model slug.",
134	      }));
135	      return;
136	    }
137	    if (getModelOptions(provider).some((option) => option.slug === normalized)) {
138	      setCustomModelErrorByProvider((existing) => ({
139	        ...existing,
140	        [provider]: "That model is already built in.",
141	      }));
142	      return;
143	    }
144	    if (normalized.length > MAX_CUSTOM_MODEL_LENGTH) {
145	      setCustomModelErrorByProvider((existing) => ({
146	        ...existing,
147	        [provider]: `Model slugs must be ${MAX_CUSTOM_MODEL_LENGTH} characters or less.`,
148	      }));
149	      return;
150	    }
151	    if (customModels.includes(normalized)) {
152	      setCustomModelErrorByProvider((existing) => ({
153	        ...existing,
154	        [provider]: "That custom model is already saved.",
155	      }));
156	      return;
157	    }
158	
159	    updateSettings(patchCustomModels(provider, [...customModels, normalized]));
160	    setCustomModelInputByProvider((existing) => ({
161	      ...existing,
162	      [provider]: "",
163	    }));
164	    setCustomModelErrorByProvider((existing) => ({
165	      ...existing,
166	      [provider]: null,
167	    }));
168	  }, [customModelInputByProvider, settings, updateSettings]);
169	
170	  const removeCustomModel = useCallback(
171	    (provider: ProviderKind, slug: string) => {
172	      const customModels = getCustomModelsForProvider(settings, provider);
173	      updateSettings(patchCustomModels(provider, customModels.filter((model) => model !== slug)));
174	      setCustomModelErrorByProvider((existing) => ({
175	        ...existing,
176	        [provider]: null,
177	      }));
178	    },
179	    [settings, updateSettings],
180	  );
181	
182	  return (
183	    <SidebarInset className="h-dvh min-h-0 overflow-hidden overscroll-y-none bg-background text-foreground isolate">
184	      <div className="flex min-h-0 min-w-0 flex-1 flex-col bg-background text-foreground">
185	        {isElectron && (
186	          <div className="drag-region flex h-[52px] shrink-0 items-center border-b border-border px-5">
187	            <span className="text-xs font-medium tracking-wide text-muted-foreground/70">
188	              Settings
189	            </span>
190	          </div>
191	        )}
192	
193	        <div className="flex-1 overflow-y-auto p-6">
194	          <div className="mx-auto flex w-full max-w-3xl flex-col gap-6">
195	            <header className="space-y-1">
196	              <h1 className="text-2xl font-semibold tracking-tight text-foreground">Settings</h1>
197	              <p className="text-sm text-muted-foreground">
198	                Configure app-level preferences for this device.
199	              </p>
200	            </header>
201	
202	            <section className="rounded-2xl border border-border bg-card p-5">
203	              <div className="mb-4">
204	                <h2 className="text-sm font-medium text-foreground">Appearance</h2>
205	                <p className="mt-1 text-xs text-muted-foreground">
206	                  Choose how T3 Code handles light and dark mode.
207	                </p>
208	              </div>
209	
210	              <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
211	                {THEME_OPTIONS.map((option) => {
212	                  const selected = theme === option.value;
213	                  return (
214	                    <button
215	                      key={option.value}
216	                      type="button"
217	                      role="radio"
218	                      aria-checked={selected}
219	                      className={`flex w-full items-start justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
220	                        selected
221	                          ? "border-primary/60 bg-primary/8 text-foreground"
222	                          : "border-border bg-background text-muted-foreground hover:bg-accent"
223	                      }`}
224	                      onClick={() => setTheme(option.value)}
225	                    >
226	                      <span className="flex flex-col">
227	                        <span className="text-sm font-medium">{option.label}</span>
228	                        <span className="text-xs">{option.description}</span>
229	                      </span>
230	                      {selected ? (
231	                        <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
232	                          Selected
233	                        </span>
234	                      ) : null}
235	                    </button>
236	                  );
237	                })}
238	              </div>
239	
