  statusBar: "oklch(0.488 0.217 264)",
  statusBarForeground: "oklch(1.000 0 0)",
};

const T3_MIDNIGHT_PALETTE: ThemeColorPalette = {
  background: "oklch(0.085 0.020 270)",
  foreground: "oklch(0.880 0.018 290)",
  card: "oklch(0.105 0.018 270)",
  cardForeground: "oklch(0.880 0.018 290)",
  accent: "oklch(0.720 0.180 300)",
  accentForeground: "oklch(0.100 0.010 270)",
  sidebar: "oklch(0.070 0.018 270)",
  sidebarForeground: "oklch(0.880 0.018 290)",
  editor: "oklch(0.095 0.016 270)",
  editorForeground: "oklch(0.880 0.018 290)",
  terminal: "oklch(0.065 0.015 270)",
  terminalForeground: "oklch(0.820 0.015 290)",
  statusBar: "oklch(0.260 0.060 270)",
  statusBarForeground: "oklch(0.720 0.180 300)",
};

// ---------------------------------------------------------------------------
// Theme registry
// ---------------------------------------------------------------------------

export const BUILT_IN_THEMES: AppTheme[] = [
  { id: "t3-dark", label: "Dark", isDark: true, palette: T3_DARK_PALETTE },
  { id: "t3-light", label: "Light", isDark: false, palette: T3_LIGHT_PALETTE },
  { id: "t3-midnight", label: "Midnight", isDark: true, palette: T3_MIDNIGHT_PALETTE },
];

export const THEME_LOOKUP: Record<string, AppTheme> = Object.fromEntries(
  BUILT_IN_THEMES.map((t) => [t.id, t]),
);

// ---------------------------------------------------------------------------
// CSS variable mapping
// ---------------------------------------------------------------------------

/**
 * Maps a ThemeColorPalette onto the full set of CSS custom properties consumed
 * by index.css and the Tailwind @theme inline block.
 *
 * Using style.setProperty() at the root element wins over all class-based CSS
 * rules (including @variant dark), giving each theme complete independence.
 */
export function buildThemeCssVars(
  palette: ThemeColorPalette,
  isDark: boolean,
): Record<string, string> {
  // Base alpha for transparent derivatives (white on dark, black on light)
  const alphaBase = isDark ? "oklch(1 0 0" : "oklch(0 0 0";
  const mutedFg = isDark ? "oklch(0.650 0.010 264)" : "oklch(0.550 0.010 264)";

  return {
    // Core canvas
    "--background": palette.background,
    "--foreground": palette.foreground,
    // Card / popover surfaces
    "--card": palette.card,
    "--card-foreground": palette.cardForeground,
    "--popover": palette.card,
    "--popover-foreground": palette.cardForeground,
    // Primary interactive colour
    "--primary": palette.accent,
    "--primary-foreground": palette.accentForeground,
    "--ring": palette.accent,
    // Derived neutral surfaces (semi-transparent overlays)
    "--secondary": `${alphaBase} / 4%)`,
    "--secondary-foreground": palette.foreground,
    "--muted": `${alphaBase} / 4%)`,
    "--muted-foreground": mutedFg,
    "--accent": `${alphaBase} / 4%)`,
    "--accent-foreground": palette.foreground,
    // Structural chrome
    "--border": `${alphaBase} / ${isDark ? "6%" : "8%"})`,
    "--input": `${alphaBase} / ${isDark ? "8%" : "10%"})`,
    // Extended palette: sidebar, editor, terminal, status bar
    "--sidebar": palette.sidebar,
    "--sidebar-foreground": palette.sidebarForeground,
    "--editor": palette.editor,
    "--editor-foreground": palette.editorForeground,
    "--terminal": palette.terminal,
    "--terminal-foreground": palette.terminalForeground,
    "--status-bar": palette.statusBar,
    "--status-bar-foreground": palette.statusBarForeground,
  };
}

