import { useCallback, useEffect, useSyncExternalStore } from "react";
import type { AppThemeId, BuiltInThemeId, ThemeColorPalette } from "@t3tools/contracts";
import { THEME_LOOKUP, buildThemeCssVars } from "../themes";

export type { AppThemeId };

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

type ThemeSnapshot = {
  themeId: AppThemeId;
  systemDark: boolean;
};

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStored(): AppThemeId {
  const raw = localStorage.getItem(STORAGE_KEY);
  // Migrate legacy values stored before the named theme system
  if (raw === "dark") return "t3-dark";
  if (raw === "light") return "t3-light";
  if (raw === "t3-dark" || raw === "t3-light" || raw === "t3-midnight" || raw === "system") {
    return raw;
  }
  return "system";
}

function resolveThemeId(themeId: AppThemeId, systemDark: boolean): BuiltInThemeId {
  if (themeId === "system") return systemDark ? "t3-dark" : "t3-light";
  return themeId;
}

function applyTheme(themeId: AppThemeId, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const resolvedId = resolveThemeId(themeId, getSystemDark());
  const theme = THEME_LOOKUP[resolvedId];

  if (theme) {
    // Toggle .dark so all existing Tailwind dark: utilities keep working
    document.documentElement.classList.toggle("dark", theme.isDark);
    // Inject CSS vars via inline style — highest specificity, overrides @variant dark
    const vars = buildThemeCssVars(theme.palette, theme.isDark);
    for (const [key, value] of Object.entries(vars)) {
      document.documentElement.style.setProperty(key, value);
    }
  } else {
    document.documentElement.classList.toggle("dark", getSystemDark());
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

function getSnapshot(): ThemeSnapshot {
  const themeId = getStored();
  const systemDark = themeId === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.themeId === themeId &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { themeId, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = snapshot.themeId;
  const systemDark = snapshot.systemDark;

  const resolvedId = resolveThemeId(theme, systemDark);
  const resolvedTheme: BuiltInThemeId = resolvedId;
  const resolvedPalette: ThemeColorPalette | null = THEME_LOOKUP[resolvedId]?.palette ?? null;

  const setTheme = useCallback((next: AppThemeId) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, resolvedTheme, resolvedPalette } as const;
}

