import type { AppThemeId, ThemeColorPalette } from "@t3tools/contracts";
import { BUILT_IN_THEMES, THEME_LOOKUP } from "../themes";

interface ThemeSelectorProps {
  value: AppThemeId;
  onChange: (id: AppThemeId) => void;
}

// ---------------------------------------------------------------------------
// Swatch previews
// ---------------------------------------------------------------------------

/** Miniature three-zone UI preview: sidebar | editor + status bar */
function ThemeSwatch({ palette }: { palette: ThemeColorPalette }) {
  return (
    <div className="h-11 w-full overflow-hidden rounded-md" aria-hidden="true">
      {/* Sidebar + editor row */}
      <div className="flex h-[calc(100%-12px)]">
        <div className="w-[28%] shrink-0" style={{ background: palette.sidebar }} />
        <div className="flex-1" style={{ background: palette.editor }} />
      </div>
      {/* Status bar strip */}
      <div
        className="flex h-3 items-center px-1.5"
        style={{ background: palette.statusBar }}
      >
        <div
          className="h-[3px] w-5 rounded-full"
          style={{ background: palette.statusBarForeground, opacity: 0.6 }}
        />
        <div
          className="ml-auto h-[3px] w-2 rounded-full"
          style={{ background: palette.statusBarForeground, opacity: 0.35 }}
        />
      </div>
    </div>
  );
}

/** Split swatch showing light (left) and dark (right) halves for the System option */
function SystemSwatch() {
  const light = THEME_LOOKUP["t3-light"];
  const dark = THEME_LOOKUP["t3-dark"];
  if (!light || !dark) return null;
  const lp = light.palette;
  const dp = dark.palette;
  return (
    <div className="h-11 w-full overflow-hidden rounded-md" aria-hidden="true">
      <div className="flex h-full">
        {/* Light half */}
        <div className="flex h-full w-1/2 flex-col">
          <div className="flex flex-1">
            <div className="w-[28%] shrink-0" style={{ background: lp.sidebar }} />
            <div className="flex-1" style={{ background: lp.editor }} />
          </div>
          <div className="h-3" style={{ background: lp.statusBar }} />
        </div>
        {/* Divider */}
        <div className="w-px shrink-0 bg-black/10" />
        {/* Dark half */}
        <div className="flex h-full w-1/2 flex-col">
          <div className="flex flex-1">
            <div className="w-[28%] shrink-0" style={{ background: dp.sidebar }} />
            <div className="flex-1" style={{ background: dp.editor }} />
          </div>
          <div className="h-3" style={{ background: dp.statusBar }} />
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// ThemeSelector
// ---------------------------------------------------------------------------

export function ThemeSelector({ value, onChange }: ThemeSelectorProps) {
  const options: Array<{ id: AppThemeId; label: string; preview: React.ReactNode }> = [
    { id: "system", label: "System", preview: <SystemSwatch /> },
    ...BUILT_IN_THEMES.map((theme) => ({
      id: theme.id as AppThemeId,
      label: theme.label,
      preview: <ThemeSwatch palette={theme.palette} />,
    })),
  ];

  return (
    <div className="grid grid-cols-2 gap-3 sm:grid-cols-4" role="radiogroup" aria-label="Theme preference">
      {options.map((option) => {
        const selected = value === option.id;
        return (
          <button
            key={option.id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => onChange(option.id)}
            className={`flex flex-col gap-2 rounded-xl border p-2 text-left transition-colors ${
              selected
                ? "border-primary/60 bg-primary/8 ring-1 ring-primary/40"
                : "border-border bg-background hover:bg-accent"
            }`}
          >
            {option.preview}
            <span className={`text-xs font-medium ${selected ? "text-primary" : "text-foreground"}`}>
              {option.label}
            </span>
          </button>
        );
      })}
    </div>
  );
}

