import { Schema } from "effect";

export const BUILT_IN_THEME_IDS = ["t3-dark", "t3-light", "t3-midnight"] as const;
export type BuiltInThemeId = (typeof BUILT_IN_THEME_IDS)[number];

export const AppThemeId = Schema.Literal("system", "t3-dark", "t3-light", "t3-midnight");
export type AppThemeId = typeof AppThemeId.Type;

/**
 * A concrete color palette covering 7 UI areas × 2 roles (surface + text).
 * All values are concrete CSS color strings (e.g. oklch) — no var() references —
 * so they can be rendered directly in preview swatches without any CSS resolution.
 */
export const ThemeColorPalette = Schema.Struct({
  // Main canvas
  background: Schema.String,
  foreground: Schema.String,
  // Elevated surfaces (cards, popovers)
  card: Schema.String,
  cardForeground: Schema.String,
  // Primary interactive accent
  accent: Schema.String,
  accentForeground: Schema.String,
  // Navigation sidebar
  sidebar: Schema.String,
  sidebarForeground: Schema.String,
  // Code / text editor pane
  editor: Schema.String,
  editorForeground: Schema.String,
  // Integrated terminal
  terminal: Schema.String,
  terminalForeground: Schema.String,
  // Status / activity bar
  statusBar: Schema.String,
  statusBarForeground: Schema.String,
});
export type ThemeColorPalette = typeof ThemeColorPalette.Type;

export const AppTheme = Schema.Struct({
  id: Schema.Literals(BUILT_IN_THEME_IDS),
  label: Schema.String,
  isDark: Schema.Boolean,
  palette: ThemeColorPalette,
});
export type AppTheme = typeof AppTheme.Type;

